// Simulated Sync Connection State Variables
let isOnlineSimulated = true;

window.handleTeacherLogin = function(e) {
    if (e) e.preventDefault();
    const idInput = document.getElementById('teacher-login-id').value.trim();
    const pwInput = document.getElementById('teacher-login-password').value.trim();

    if (idInput === 'teacher' && pwInput === '1234') {
        sessionStorage.setItem('lms-teacher-auth', 'true');
        const overlay = document.getElementById('teacher-login-overlay');
        if (overlay) overlay.style.setProperty('display', 'none', 'important');
        showToast('เข้าสู่ระบบสำเร็จ', 'ยินดีต้อนรับคุณครูเข้าสู่ระบบจัดการ', 'success');
    } else {
        const errEl = document.getElementById('teacher-login-error');
        if (errEl) errEl.style.display = 'block';
    }
};

window.quickTeacherLogin = function() {
    document.getElementById('teacher-login-id').value = 'teacher';
    document.getElementById('teacher-login-password').value = '1234';
    handleTeacherLogin();
};

window.handleTeacherLogout = function() {
    sessionStorage.removeItem('lms-teacher-auth');
    window.location.href = 'index.html';
};

let lastSyncTime = new Date().toLocaleTimeString('th-TH', { hour: '2-digit', minute: '2-digit' });

